import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Store, Plus, Loader2, Package, ImageIcon } from 'lucide-react';
import { api } from '../services/api';
import { useCart } from '../context/CartContext';

// Constantes iguales a las de tu GestionOfertas.js
const CLOUD_NAME = "dwpgncjgn"; 

const PanelCliente = () => {
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const [loading, setLoading] = useState(true);
    const { addToCart, count, total } = useCart();

    useEffect(() => {
        const cargarDatos = async () => {
            try {
                setLoading(true);
                const data = await api.getTodasLasOfertas();
                
                const agrupado = data.reduce((acc, oferta) => {
                    const localData = oferta.local || {};
                    const nombreLocal = localData.nombre || 'Sucursal';
                    if (!acc[nombreLocal]) acc[nombreLocal] = { info: localData, productos: [] };
                    acc[nombreLocal].productos.push(oferta);
                    return acc;
                }, {});

                setOfertasPorLocal(agrupado);
            } catch (err) {
                console.error("Error al cargar:", err);
            } finally {
                setLoading(false);
            }
        };
        cargarDatos();
    }, []);

    // --- ESTA ES LA FUNCIÓN CLAVE QUE USA TU VENDEDOR ---
    const construirUrlImagen = (publicId) => {
        if (!publicId || publicId === 'placeholder_id') return null;
        // Construimos la URL de Cloudinary tal cual lo hace GestionOfertas.js
        return `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_400,h_300,c_fill,f_auto,q_auto/${publicId}`;
    };

    if (loading) return (
        <div style={centerState}>
            <Loader2 size={40} color="#e67e22" className="animate-spin" />
            <p>Buscando ofertas...</p>
        </div>
    );

    return (
        <div style={container}>
            <header style={headerStyle}>
                <h1 style={titleStyle}>Ofertas del Día</h1>
                <div style={cartFloatingCard}>
                    <ShoppingCart color="#e67e22" size={20} />
                    <span style={{fontWeight: 'bold'}}>${total.toLocaleString()}</span>
                    <div style={badgeCount}>{count}</div>
                </div>
            </header>

            {Object.keys(ofertasPorLocal).map(nombre => (
                <div key={nombre} style={localSection}>
                    <div style={localHeader}>
                        <Store size={20} color="#1e293b" />
                        <div>
                            <h2 style={localTitle}>{nombre}</h2>
                            <p style={localSub}>{ofertasPorLocal[nombre].info?.direccion}</p>
                        </div>
                    </div>

                    <div style={scrollContainer}>
                        {ofertasPorLocal[nombre].productos.map(prod => {
                            const urlImagen = construirUrlImagen(prod.publicId);
                            
                            return (
                                <div key={prod._id} style={productCard}>
                                    <div style={imageBox}>
                                        {urlImagen ? (
                                            <img 
                                                src={urlImagen} 
                                                alt={prod.producto} 
                                                style={imgStyle}
                                                onError={(e) => { e.target.style.display = 'none'; e.target.parentNode.style.background = '#f1f5f9'; }}
                                            />
                                        ) : (
                                            <div style={placeholderIcon}>
                                                <Package size={40} color="#cbd5e1" />
                                            </div>
                                        )}
                                        
                                        <div style={stockBadge(prod.stock)}>
                                            {prod.stock > 0 ? `${prod.stock} disp.` : 'Agotado'}
                                        </div>
                                    </div>

                                    <div style={infoBox}>
                                        <div style={categoryTag}>{prod.categoria}</div>
                                        <h4 style={prodTitle}>{prod.producto}</h4>
                                        <div style={priceContainer}>
                                            <span style={newPrice}>${prod.precioNuevo}</span>
                                            <span style={oldPrice}>${prod.precioViejo}</span>
                                        </div>
                                        <button 
                                            style={prod.stock > 0 ? btnAdd : btnDisabled}
                                            onClick={() => addToCart(prod)}
                                            disabled={prod.stock <= 0}
                                        >
                                            <Plus size={16} /> Agregar
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            ))}
        </div>
    );
};

// --- ESTILOS (Sincronizados con el look profesional del Vendedor) ---
const container = { padding: '20px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'system-ui, -apple-system, sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const titleStyle = { fontSize: '2rem', fontWeight: '900', color: '#1e293b', margin: 0 };
const cartFloatingCard = { background: '#1e293b', color: 'white', padding: '12px 24px', borderRadius: '50px', display: 'flex', alignItems: 'center', gap: '15px', boxShadow: '0 10px 20px rgba(0,0,0,0.1)' };
const badgeCount = { background: '#e67e22', color: 'white', padding: '2px 10px', borderRadius: '10px', fontSize: '0.8rem', fontWeight: 'bold' };

const localSection = { marginBottom: '50px' };
const localHeader = { display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' };
const localTitle = { margin: 0, fontSize: '1.3rem', color: '#1e293b', fontWeight: 'bold' };
const localSub = { margin: 0, fontSize: '0.85rem', color: '#94a3b8' };

const scrollContainer = { display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '20px', scrollSnapType: 'x mandatory' };
const productCard = { minWidth: '240px', background: 'white', borderRadius: '24px', border: '1px solid #e2e8f0', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', scrollSnapAlign: 'start' };
const imageBox = { height: '160px', background: '#f8fafc', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const placeholderIcon = { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px' };
const stockBadge = (stock) => ({ position: 'absolute', top: '12px', right: '12px', background: stock > 0 ? '#22c55e' : '#ef4444', color: 'white', fontSize: '0.7rem', padding: '4px 10px', borderRadius: '8px', fontWeight: 'bold' });

const infoBox = { padding: '20px' };
const categoryTag = { fontSize: '0.65rem', color: '#e67e22', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '8px', letterSpacing: '0.5px' };
const prodTitle = { margin: '0 0 12px 0', fontSize: '1.1rem', fontWeight: '700', color: '#1e293b', textTransform: 'capitalize' };
const priceContainer = { display: 'flex', alignItems: 'baseline', gap: '10px', marginBottom: '20px' };
const newPrice = { fontSize: '1.5rem', fontWeight: '900', color: '#1e293b' };
const oldPrice = { fontSize: '0.9rem', color: '#94a3b8', textDecoration: 'line-through' };

const btnAdd = { width: '100%', background: '#1e293b', color: 'white', border: 'none', padding: '12px', borderRadius: '14px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontWeight: 'bold', transition: '0.2s' };
const btnDisabled = { ...btnAdd, background: '#f1f5f9', color: '#94a3b8', cursor: 'not-allowed' };
const centerState = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '80vh', color: '#64748b' };

export default PanelCliente;
